import { readFileSync } from 'node:fs';
const strategy=readFileSync('packages/agent-core/src/agent/compaction/strategy.ts','utf8');
const cos=readFileSync('packages/agent-core/src/agent/context-os/index.ts','utf8');
const footer=readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const recovery=readFileSync('packages/agent-core/src/ultrawork/recovery-injectors.ts','utf8');
const bash=readFileSync('packages/agent-core/src/tools/builtin/shell/bash.md','utf8');
const fails=[];
if (!strategy.includes('DEFAULT_COMPACTION_TRIGGER_RATIO = 0.80')) fails.push('soft80');
if (!strategy.includes('DEFAULT_ASYNC_COMPACTION_TRIGGER_RATIO = 0.70')) fails.push('async70');
if (!cos.includes('formatContinuityOperatorNote')) fails.push('continuity-note');
if (!cos.includes('missing durable evidence')) fails.push('missing-ev-note');
if (!cos.includes('MAX_INJECTION_CHARS = 3_500')) fails.push('inject-budget');
if (!footer.includes('ctx-os:missing-ev×')) fails.push('footer-missing-ev');
if (!recovery.includes("variant: 'ultrawork_post_swarm'")) fails.push('post-swarm');
const continuityHits = recovery.split('formatContinuityOperatorNote(agent.contextOS.health())').length - 1;
if (continuityHits < 2) fails.push('post-swarm-continuity');
if (bash.length > 2200) fails.push('bash-desc-bloat');
if (!bash.includes('Prefer dedicated tools')) fails.push('bash-routing');
if (fails.length){console.error(fails.join(',')); process.exit(1);} console.log('long-session-continuity-ok');
